INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68028114e3c98b0941765e4a', '羡慕花园里的鱼??建议升级引导粉裙小姐姐服装、房间中式元素、进大门玻璃转门', '["https://dimg04.c-ctrip.com/images/0232412000ap5ktk2E135_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-21', '城央绿意大床房', '大床房', '商务出差', 37, 0, 15, 3, '["公共设施","房间设施"]'::jsonb, '公共设施', '房间设施', NULL),
('68028114e3c98b0941765e4b', '外部环境非常好！房间装修太老了！', '["https://dimg04.c-ctrip.com/images/0230212000auct2n547F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236o12000aud3vk3DCEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000aucshnkA8C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000aucnzcsF671_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000auct2n67D19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000auczfwhCEE6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-04-03', '花园双床房', '双床房', '商务出差', 16, 0, 60, 5, '["房间设施","景观/朝向"]'::jsonb, '房间设施', '景观/朝向', NULL),
('68028114e3c98b0941765e4c', '服务态度很不错，住的很舒服，大堂马卡龙很好吃，12块一个性价比不错，免费升级了套房，很不错！！！！！', '["https://dimg04.c-ctrip.com/images/0236212000aitmu9f3163_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234312000aitna0wE503_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000aitojlfFE1A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000aitmc1wE04C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000aitmtrdABDC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000aitmbhl0FA6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '城央绿意双床房', '双床房', '家庭亲子', 50, 0, 4, 7, '["前台服务","整体满意度","性价比"]'::jsonb, '前台服务', '整体满意度', '性价比'),
('68028114e3c98b0941765e4d', '服务不错 特别是kiki 交通便利 房间清洁阿姨服务也很好', '["https://dimg04.c-ctrip.com/images/0236g12000aqo7y1b8F2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-05', '花园大床房', '大床房', '独自旅行', 29, 0, 2, 5, '["前台服务","交通便利性","客房服务"]'::jsonb, '前台服务', '交通便利性', '客房服务'),
('68028114e3c98b0941765e4e', '大理石贴近壁画印象深刻 花园酒店给我的感觉就是经典 极具韵味 底蕴深厚 又与时俱进', '["https://dimg04.c-ctrip.com/images/0230k12000aptyccdE8A5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000apu0ame8BBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000aptvf6e2CC2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000aptron67018_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000aptxm0516C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000aptvnjo057B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236z12000aptyw9r19AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236t12000apu10c615CF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-26', '花园双床房', '双床房', '家庭亲子', 41, 0, 17, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028114e3c98b0941765e4f', '酒店环境非常棒，后花园，博物馆都很好逛。前厅接待的susan非常好，因为朋友生日，帮我们争取了加床，早餐，水果，蛋糕，房间布置等福利。客务部的卢小姐帮我们延迟退房。入住体验很不错。唯一不足，卫生间地漏有味道，希望改进。', '["https://dimg04.c-ctrip.com/images/0233f12000ceph8bv101B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235312000ceph35g1CBF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000ceph3k24186_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-17', '红棉双床套房', '套房', '朋友出游', 109, 0, 2, 9, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('68028114e3c98b0941765e50', '春节去的，年味很浓，酒店各方面都不错，出行也方便，以后还会选择，对广州旅游景点非常满意，以后每年都想来', '["https://dimg04.c-ctrip.com/images/0234s12000anx4ca62EAC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 51, 0, 1, 5, '["整体满意度","交通便利性","周边配套"]'::jsonb, '整体满意度', '交通便利性', '周边配套'),
('68028114e3c98b0941765e52', '位置很方便，出门就是地铁口，对面就是广州酒家。过年期间新春氛围浓。据说酒店早茶很好吃，没来得及尝试。', '["https://dimg04.c-ctrip.com/images/0230112000axj898q8DEB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a12000axj71ks9CAD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-13', '城央绿意双床房', '双床房', '朋友出游', 50, 0, 14, 6, '["交通便利性","周边配套","餐饮设施"]'::jsonb, '交通便利性', '周边配套', '餐饮设施'),
('68028114e3c98b0941765e53', '升级了行政房，酒店一如既往，每次来广州都住在这里。三楼饮茶的环境也极好，和熙熙攘攘的茶楼有不同的体验。', '["https://dimg04.c-ctrip.com/images/0234i12000ah9dqkv1964_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000ah9fpgx3B05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000ah9e6ac449B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-21', '花园大床房', '大床房', '家庭亲子', 51, 0, 45, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('6802811fe3c98b0941765e54', '过年期间酒店过节气氛很浓，大堂也一直有小活动可以参与。房间是对道路一侧的，隔音也不错，睡的很好??', '["https://dimg04.c-ctrip.com/images/0234y12000aiyi9jpD9A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-28', '花园大床房', '大床房', '朋友出游', 49, 0, 6, 6, '["安静程度","整体满意度"]'::jsonb, '安静程度', '整体满意度', NULL),
('6802811fe3c98b0941765e55', '入住时前台Kate帮忙办理入位，态度极佳，服务到位。花园酒店的房间棒极了，床虽软但托身很稳，睡得很好。有两个盥洗台，一个淋雨房，一个厕所房。离店时不用去前台办理手续，交给礼仪小姐小花即可，非常方便亲切！', '["https://dimg04.c-ctrip.com/images/0236612000ar7ibtqB14B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000ar7oixk4FA0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000ar7i0738A97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230612000ar7ksd7DE2F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000ar7khmn4A3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000ar7ocg13E6B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h12000ar7k5hp4759_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-09', '红棉双床套房', '套房', '家庭亲子', 101, 0, 11, 9, '["前台服务","房间设施","退房/入住效率"]'::jsonb, '前台服务', '房间设施', '退房/入住效率'),
('6802811fe3c98b0941765e56', 'Kiki 服务周到 送了小礼物 很喜欢花园酒店', '["https://dimg04.c-ctrip.com/images/0237012000ar6vfti5988_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-09', '粤韵双床套房', '套房', '商务出差', 23, 0, 8, 4, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802811fe3c98b0941765e57', '前台的Betty热情接待，因为是携程钻石卡主动帮我们升级套房，很舒服。房间套餐送的下午茶在行政酒廊，服务员Cherry很热情，总体感觉很满意', '["https://dimg04.c-ctrip.com/images/0231u12000afnen9sCAD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000afnca077475_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000afnckh98A44_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000afnez84315C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-13', '花园双床房', '双床房', '家庭亲子', 70, 1, 8, 7, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('6802811fe3c98b0941765e58', '酒店环境卫生很干净 服务很好??', '["https://dimg04.c-ctrip.com/images/0234g12000ast7insB4AA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000ast52915C95_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-22', '城央绿意大床房', '大床房', '商务出差', 16, 0, 3, 4, '["卫生状况","前台服务"]'::jsonb, '卫生状况', '前台服务', NULL),
('6802811fe3c98b0941765e59', '服务一流，好方便', '["https://dimg04.c-ctrip.com/images/0233a12000avykz4q4D81_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-04-08', '城央绿意双床房', '双床房', '家庭亲子', 8, 0, 6, 3, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('6802811fe3c98b0941765e5a', '房间干净，维护的很好，前台小邓非常热情，服务态度好，瀑布餐厅的下午茶也很棒，泳池服务很棒，愉快的入住体验，', '["https://dimg04.c-ctrip.com/images/0233i12000evfr3zb3781_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000evfo1e789EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000evfevz97D19_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-23', '红棉双床套房', '套房', '家庭亲子', 53, 0, 4, 7, '["卫生状况","前台服务","整体满意度"]'::jsonb, '卫生状况', '前台服务', '整体满意度'),
('6802811fe3c98b0941765e5c', '花园酒店是我当年在广州上大学时就与白天鹅并列的五星酒店天花板。三十多年过去了，她依然是广州的酒店顶流！这次入住的粤韵房是新装修的，设施先进，这次还享受了行政酒廊礼遇。春天的花城温暖和煦，酒店花园里鲜花盛开，我们还顺便参观了酒店四楼的“酒店博物馆”，涨了知识，整个入住体验非常好，下次来广州还住花园！顺便表扬行政酒廊帅哥小贺，服务周到、礼貌、儒雅，让人如沐春风！', '["https://dimg04.c-ctrip.com/images/0236t12000aoujj7p9C49_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000aouf8h4D3B5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000aouihp76331_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000aoudcwy68B5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-19', '红棉大床套房', '套房', '家庭亲子', 180, 0, 16, 9, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('6802811fe3c98b0941765e5d', '交通方便，地铁出来就是酒店，外观非常气派，大堂布置很特别，吸引打卡。房间卫生干净，岭南特色设计，服务员都热情打招呼，有礼貌，特别是楼层服务员张小燕送了甜点，味道很好。胡主管能详细介绍酒店餐厅和其他设施，给我的入住带来惊喜和方便，性价比高，下次还来！', '["https://dimg04.c-ctrip.com/images/0232m12000c46uxtn5CD8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000c46m5vd1FBB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-12', '花园大床房', '大床房', '独自旅行', 124, 0, 3, 9, '["交通便利性","卫生状况","性价比"]'::jsonb, '交通便利性', '卫生状况', '性价比'),
('6802812be3c98b0941765e5f', '前台热情，免费升级了套房，房间干净卫生，床品很舒服，1楼花园餐厅环境优美，三楼本地特色餐厅值得品尝，广交会期间人很多 但服务依然到位', '["https://dimg04.c-ctrip.com/images/0232h12000g8n54l6D38A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000g8ml8dc7889_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000g8nex4gB60F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000g8nbmxd2966_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-10-21', '花园双床房', '双床房', '其他', 66, 0, 15, 8, '["前台服务","卫生状况","餐饮设施"]'::jsonb, '前台服务', '卫生状况', '餐饮设施'),
('6802812be3c98b0941765e60', '由一个意外开始，却因此获得了一次真正五星的体验，不愧老牌五星酒店，实力推荐，下次来广州基本不考虑其他酒店了', '["https://dimg04.c-ctrip.com/images/0236312000adqkusvA1AF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-05', '红棉大床套房', '套房', '家庭亲子', 53, 0, 27, 6, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802812be3c98b0941765e61', '服务：态度决定酒店的一切！非常好??
卫生：好
环境：好
服务：好', '["https://dimg04.c-ctrip.com/images/0236t12000anyexmd9751_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000anyn1gh1FF3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '花园双床房', '双床房', '家庭亲子', 33, 0, 7, 2, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况'),
('6802812be3c98b0941765e63', '家庭周末出游，酒店位置优越，服务周到，非常满意。', '["https://dimg04.c-ctrip.com/images/0232d12000aptqnpj0DDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u12000aptqp1qB570_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000aptqp8gE2D6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000aptqr5cA33A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-26', '花园双床房', '双床房', '家庭亲子', 24, 0, 25, 4, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('6802812be3c98b0941765e64', '非常好 孩子最喜欢的酒店 下次到广州还是首先花园酒店', '["https://dimg04.c-ctrip.com/images/0230k12000ar1jh52E87C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230i12000ar1oa5r428B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-08', '羊羊得意主题大床房', '主题房', '家庭亲子', 26, 0, 28, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802812be3c98b0941765e65', '房间质素高，酒店的专属管家小何非常热情，入住时给客人的照顾十分周到，针对旅游客人，还把酒店的所有打卡点都介绍到了，否则客人还不知道花园酒店里就有这么多历史参观点，优秀！

花园酒店显然经过精心设计，除了是个休憩落脚的好去处，本身就包含丰富的历史内涵，从酒店的成立到发展，景观的布置，餐厅的设置，都与广州这个古老的城市文化深度绑定，在广州这么多传统酒店里是非常突出的代表。花园酒店还设置了一个酒店博物馆，讲述酒店在这片土地的变迁发展，更是将广州的近代历程都浓缩一所，非常值得去看看。', '["https://dimg04.c-ctrip.com/images/0234412000ewypiabBC3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000ewylsceCB77_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235z12000ewykamaF9E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000ewyn48008DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-27', '花园大床房', '大床房', '朋友出游', 240, 0, 2, 9, '["前台服务","整体满意度","公共设施"]'::jsonb, '前台服务', '整体满意度', '公共设施'),
('6802812be3c98b0941765e66', '酒店的后花园非常不错，二楼三楼的米其林餐厅也很棒！谢谢前台betty的服务，办理速度很快。这次住宿很满意！', '["https://dimg04.c-ctrip.com/images/0230312000ce8el7n6EED_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000ce8aymp80FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000ce8e4wl01BB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-15', '花园大床房', '大床房', '商务出差', 53, 0, 16, 7, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('6802813ce3c98b0941765e68', '环境好,服务态度好,免费upgrade房间', '["https://dimg04.c-ctrip.com/images/0232w12000aqfnqbf700D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000aqfmkby890F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000aqfknpyFB3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000aqfpoq514FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000aqfq9yt186C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000aqfq0k88077_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-03', '花园双床房', '双床房', '商务出差', 21, 0, 1, 5, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('6802813ce3c98b0941765e6a', '喜欢这个美丽的酒店，留下非常美好的印象。酒店博物馆很棒！', '["https://dimg04.c-ctrip.com/images/0234l12000ao9bz19BCEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000ao9bwbz3CC5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000ao9bum2370D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000ao9bu6t027F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000ao9bxw5F0AD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000ao9bu6wC395_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-15', '花园大床房', '大床房', '独自旅行', 28, 0, 10, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802813ce3c98b0941765e6b', '老牌酒店值得信赖，入住退房都非常好，房间也不错，春节期间体验感最好的一家酒店。', '["https://dimg04.c-ctrip.com/images/0234g12000ahxda6542A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000ahxd0yoA4DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000ahxd67q9C08_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-24', '花园大床房', '大床房', '家庭亲子', 39, 0, 9, 5, '["整体满意度","退房/入住效率","房间设施"]'::jsonb, '整体满意度', '退房/入住效率', '房间设施'),
('6802813ce3c98b0941765e6c', '从成都旅游回来临时起意来广州花园酒店，晚上到店后，Joe帅哥的服务态度很好，说话很有礼貌，还为我们升级了套房，在这里非常的感谢Joe小哥。
房间的装修很有格调，进门的厕所设计很细节，客人进来房间就不会看到睡觉的地方，办公的小房间还有健身器材确实考虑了作为住店客人的日常生活需要。洗手间很大气，非常喜欢，设计感也很强。明显加装的马桶智能盖板才让我感觉到了酒店的年代感，和洗手台淋浴间一对比，很难想象这是一家1985年开业的酒店，至今内部的装修依旧不过时甚至可以说走到潮流一线。
由于第二天睡过头错过了最爱的酒店早餐，中午去了荔湾亭，虽然有段时间没有来花园酒店的荔湾亭吃饭，但是它的出品依旧在线，非常好评（如果不在意价格的话）。总的来说这次住店体验非常的好，作为广州的招牌之一花园酒店名副其实。最后再次感谢Joe小哥的热情接待。', '["https://dimg04.c-ctrip.com/images/0235v12000akecrnbB281_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000ake7mv9E9C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000akerny055DA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000ake9336CDEA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000akednon66B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235x12000aket0b946C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000akeapsp3E7A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000akeh3xjBC52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000akeggv5EEEA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-02', '城央绿意大床房', '大床房', '情侣出游', 362, 0, 2, 9, '["前台服务","房间设施","整体满意度"]'::jsonb, '前台服务', '房间设施', '整体满意度'),
('6802813ce3c98b0941765e6d', '广州花园酒店名不虚传，服务态度也太好了叭，特别是前厅部的吴灵伶，入住的时候是她接待我的。服务态度和微笑深深融化了我的心，房间设备非常齐全，卫生也打扫的很棒，干干净净的，为这个酒店点赞，满分。续住碰到前台小妹Betty，潮汕热情的妹妹，点赞！！！', '["https://dimg04.c-ctrip.com/images/0232712000j7xxe3i526C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000j7x6vdi57CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000j7vho3tF4EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236f12000j7wstcz6474_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-21', '城央绿意大床房', '大床房', '朋友出游', 122, 0, 1, 8, '["前台服务","房间设施","卫生状况"]'::jsonb, '前台服务', '房间设施', '卫生状况'),
('6802813ce3c98b0941765e6f', '攻略了好久在白天鹅之间反复纠结，最后决定住花园。瀑布餐厅蛮有意思的（中间还有个大关公），咖啡豆不错。感谢前台小哥billy的细心接待，酒店出门就是地铁口去哪儿都很方便，周围吃的也多，下次来广州还选花园', '["https://dimg04.c-ctrip.com/images/0233r12000c32w90n2134_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000c32vulb5D5C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000c32w3ss2BF7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-07', '花园大床房', '大床房', '独自旅行', 100, 1, 1, 7, '["交通便利性","前台服务","周边配套"]'::jsonb, '交通便利性', '前台服务', '周边配套'),
('6802813ce3c98b0941765e70', '不错环境很好服务更不错', '["https://dimg04.c-ctrip.com/images/0233u12000asjkh004C75_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236512000asjcjhj8E42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000asjle6nAB52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000asjllfh2B18_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d12000asjkc4dE7A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-20', '花园大床房', '大床房', '情侣出游', 11, 0, 4, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802813ce3c98b0941765e71', '环境不错，地点位于越秀区中心，服务也很好，已经朋友圈安利了，小伙伴们表示值得一住。', '["https://dimg04.c-ctrip.com/images/0234s12000agq8yeu95C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000agq8qjv69F2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000agq8eikC6B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000agq8qjw9313_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000agq8ask4C19_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000agq88574AEF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000agq81pp55F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000agq7tgp63F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000agq8qjy1721_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-18', '花园双床房', '双床房', '家庭亲子', 41, 0, 9, 5, '["整体满意度","周边配套","前台服务"]'::jsonb, '整体满意度', '周边配套', '前台服务'),
('68028147e3c98b0941765e73', '老牌酒店了，第二次住，有个大花园。里面好多鱼。人挺多。', '["https://dimg04.c-ctrip.com/images/0202j12000anz14xfE244_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-13', '城央绿意双床房', '双床房', '家庭亲子', 27, 0, 21, 4, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68028147e3c98b0941765e74', '酒店很美，还有酒店博物馆，花园特别棒，要不是春节人太多，绝对是一种享受', '["https://dimg04.c-ctrip.com/images/0230z12000aidepy36B6A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000aidd9oa03CF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000aidelcg5666_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000aiddp5wE69F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-01-26', '红棉大床套房', '套房', '家庭亲子', 35, 0, 3, 6, '["公共设施","整体满意度"]'::jsonb, '公共设施', '整体满意度', NULL),
('68028147e3c98b0941765e75', '白金五星酒店名不虚传。虽然是一家老牌五星酒店，但是保养服务设施都还是非常完好的，值得入住。特别感谢前厅副理麦卓鸿先生，针对酒店延迟入住的处理方式，非常及时和妥当。为我们全家留下美好的印象。', '["https://dimg04.c-ctrip.com/images/0232m12000aitu70370DB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000aitswo9DC15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235s12000aitsapy36C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000aitqqooBD76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000aitr0dz9513_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '红棉大床套房', '套房', '家庭亲子', 94, 0, 22, 8, '["整体满意度","前台服务","房间设施"]'::jsonb, '整体满意度', '前台服务', '房间设施'),
('68028147e3c98b0941765e76', '非常棒的酒店，博物馆，后花园，瀑布餐厅，米其林餐厅都物超所值', '["https://dimg04.c-ctrip.com/images/0230w12000al6282m9521_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000ak3ew9iCF99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000al60fpvCBD1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000ak3a1gl8EFB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000al5veb49A5C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-04', '花园大床房', '大床房', '家庭亲子', 30, 0, 3, 7, '["餐饮设施","周边配套","性价比"]'::jsonb, '餐饮设施', '周边配套', '性价比'),
('68028147e3c98b0941765e77', '非常不错的一次旅行，下次有机会去广州还是花园酒店！', '["https://dimg04.c-ctrip.com/images/0236y12000anq015m9284_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000anp6xjwEE13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000anpzz729C65_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-12', '红棉大床套房', '套房', '家庭亲子', 25, 0, 8, 4, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028147e3c98b0941765e78', '一家很不错的酒店，服务态度很好，下个还会选择这家酒店住。', '["https://dimg04.c-ctrip.com/images/0235s12000alx43wjB049_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u12000alx4em72E86_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-02-06', '花园大床房', '大床房', '情侣出游', 28, 0, 4, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68028147e3c98b0941765e79', '非常棒，虽然已有一段时间了，但还是很美！', '["https://dimg04.c-ctrip.com/images/0234812000apa2xc6BECA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-22', '城央绿意大床房', '大床房', '商务出差', 20, 0, 7, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028147e3c98b0941765e7a', '服务非常好，但加钱升级套房还没有浴缸，也是醉了。', '["https://dimg04.c-ctrip.com/images/0236i12000aodwz9b0378_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000aoesl818181_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000aoepl5x549F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2023-02-16', '花园双床房', '双床房', '商务出差', 24, 0, 5, 6, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68028153e3c98b0941765e7c', '先选花园，本来大部分是为了怀旧，毕竟二十年前出差花城常住的酒店，带闺女体验下我大国改革开放之后的第一批豪华酒店。没想到倒是惊喜，酒店应该是把原来的二间房打通变成了一间客房，所以都是套间的布局。基本的硬件不多说了，细节的备品很赞，TWG的茶包Nespresso咖啡和四支屈臣氏的水，白金五星诚不我欺。花园行政酒廊的服务相当周到，热情得我会以为都是刚入行的管培生。除了前台check in排队等候的时间有点长（当然前厅部的水准还是够专业的），一切完美', '["https://dimg04.c-ctrip.com/images/0232l12000anhyofz0ED0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000anh04fmF33C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235112000angz16wB2E3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000angy9mv6DFF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-02-12', '红棉双床套房', '套房', '家庭亲子', 223, 0, 56, 9, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68028153e3c98b0941765e7d', '环境好，位置方便，服务热情，过年还准备了很多活动。很满意的一次入住！', '["https://dimg04.c-ctrip.com/images/0230i12000aioyhbgD7DE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u12000aioyqfq9DA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235d12000aioyqgk772B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235712000aioyi794996_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233512000aioyox8D9AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000aioytlzE312_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000aioyua7E739_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000aioywcn53A5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-01-27', '红棉大床套房', '套房', '独自旅行', 34, 0, 2, 6, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68028153e3c98b0941765e7f', '再次入住花园酒店，还是熟悉的味道。酒店交通极其便利，地铁站步行仅3分钟，周边商圈、美食、景点地很风格
客房环境：
入住的房间空间宽敞，装修典雅兼具现代感。
床品舒适度高，卫浴设施齐全（干湿分离），备品用的是知名品牌，细节贴心。唯一不足是临街房间稍有些噪音，建议大家选择高楼层或或向瀑布的房型。  

服务态度：★★★★★
前台和礼宾部服务热情，办理入住高效，主动介绍了酒店设施和周边推荐。尤其称赞办入住的Cecilia 和BETTY两位前台女生。客房响应速度很快，夜床服务也很细致。  

餐饮体验：
早餐种类丰富，中西式选择多，尤其推荐本地特色的早茶点心。行政酒廊的下午茶安静舒适，适合商务会谈。桃园馆中餐厅的粤菜出品稳定，但晚餐高峰期需等位，不过为了吃好吃的粤菜及特色片皮鸭值得等待', '["https://dimg04.c-ctrip.com/images/0230d12000jbsqwrz250C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000jbtchaeFCBB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000jbsqws17CF0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000jbt2w4l26FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233812000jbug1pkBF6E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-26', '花园大床房', '大床房', '商务出差', 343, 0, 14, 9, '["交通便利性","房间设施","前台服务"]'::jsonb, '交通便利性', '房间设施', '前台服务'),
('68028153e3c98b0941765e80', '前台的mikey，Elvis服务很不错，贴心的按我的要求给我安排房间，而且她们都好温柔哦，人也漂亮，超nice的小姐姐。房间很舒服，布置温馨实用。这次赶时间，下次再试酒店的餐厅，期待他们顶楼的餐厅开放。还有礼宾部的小伙子给我介绍周边的餐厅，出品都好好哦，为我这次广州之行锦上添花。', '["https://dimg04.c-ctrip.com/images/0232x12000aropu4v7359_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233n12000aroplxx987A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000arogxda97C1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-13', '花园双床房', '双床房', '朋友出游', 140, 0, 3, 8, '["前台服务","房间设施","周边配套"]'::jsonb, '前台服务', '房间设施', '周边配套'),
('68028153e3c98b0941765e81', '绝对高大上……服务态度正点……', '["https://dimg04.c-ctrip.com/images/0231t12000aqe6won5873_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234i12000aqe67bd977A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-03', '城央绿意大床房', '大床房', '商务出差', 15, 0, 2, 3, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68028153e3c98b0941765e84', '早餐真心一般，品种少，服务人员态度友善，比起内地其他五星好太多，花园漂亮。', '["https://dimg04.c-ctrip.com/images/0231a12000afnboglE658_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236v12000afnbl782841_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000afnbmgkDBB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-01-13', '花园大床房', '大床房', '独自旅行', 37, 0, 50, 5, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('6802815de3c98b0941765e87', '床垫实在是太软了，睡着不舒服。', '["https://dimg04.c-ctrip.com/images/0231b12000apy0dspD4A3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-02-27', '花园大床房', '大床房', '独自旅行', 15, 0, 1, 4, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('6802815de3c98b0941765e88', '花园酒店是我在广州的这几天住的最好的五星酒店。酒店地理位置优越，出门就是地铁。酒店内部有26个文化打卡点，还有自己的博物馆，值得好好逛一下。房间升级到一室一厅，房内摆设古色古香。值班经理Semmy特别贴心，服务细致周到，待人热情真诚。下次来广州，我一定还住花园酒店。', '["https://dimg04.c-ctrip.com/images/0230712000b7ohnlv81DD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000b7olsyv7836_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000b7oocat5AF2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230812000b7oeoad4CA0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000b7om09n7426_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000b7oh70l32D3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000b7ohcdlF597_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000b7oisfgCE39_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000b7omozjB065_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-13', '花园双床房', '双床房', '家庭亲子', 133, 3, 4, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('6802815de3c98b0941765e8d', '第一次来广州，选择了广州花园酒店，一进入大堂就有穿着特色金闪闪服装的小姐姐欢迎我，前台迅速为我处理入住手续，每天出入大堂都有员工和我微信打招呼，客房也非常干净整洁，退房还有宾客关系经理零零lavinia打回访电话，此次入住非常开心满意~', '["https://dimg04.c-ctrip.com/images/0236r12000etkd5p45C9F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000etkiubqDC3A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-18', '花园双床房', '双床房', '朋友出游', 118, 0, 2, 8, '["前台服务","整体满意度","卫生状况"]'::jsonb, '前台服务', '整体满意度', '卫生状况')
